record Order(double price, long ts) {}

// price DESC, then ts ASC (oldest first within a price level)
Comparator<Order> bids =
    Comparator.comparingDouble(Order::price).reversed()   // price descending
              .thenComparingLong(Order::ts);              // ts ascending

// Equivalent for an integral primary key, hand-rolled, no boxing:
// (a, b) -> {
//     int c = Long.compare(b.price(), a.price()); // swapped args = descending
//     return c != 0 ? c : Long.compare(a.ts(), b.ts());
