// Keep the K LARGEST of a stream without sorting everything.
// Trick: a MIN-heap of size K. The smallest of the current best-K
// sits at the head; if a new value beats it, evict the head.
static int[] topK(int[] stream, int k) {
    PriorityQueue<Integer> heap = new PriorityQueue<>(k); // min-heap
    for (int x : stream) {
        if (heap.size() < k) {
            heap.offer(x);
        } else if (x > heap.peek()) {   // beats the weakest survivor
            heap.poll();                 // drop current minimum
            heap.offer(x);
        }
    }
    // heap now holds the K largest (unordered); drain for sorted output
    int[] out = new int[heap.size()];
    for (int i = out.length - 1; i >= 0; i--) out[i] = heap.poll();
    return out; // ascending; reverse for descending
}

