import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine().trim());
        long[][] orders = new long[n][3]; // price, ts, seq
        for (int i = 0; i < n; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            orders[i][0] = Long.parseLong(st.nextToken());
            orders[i][1] = Long.parseLong(st.nextToken());
            orders[i][2] = Long.parseLong(st.nextToken());
        }
        Arrays.sort(orders, (a, b) -> {
            int c = Long.compare(b[0], a[0]); // price descending
            if (c != 0) return c;
            c = Long.compare(a[1], b[1]);     // ts ascending
            if (c != 0) return c;
            return Long.compare(a[2], b[2]);  // seq ascending
        });
        StringBuilder sb = new StringBuilder();
        for (long[] o : orders) sb.append(o[2]).append('\n');
        System.out.print(sb);
    }
}

