import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        StreamTokenizer in = new StreamTokenizer(new BufferedReader(new InputStreamReader(System.in)));
        in.nextToken(); int n = (int) in.nval;
        in.nextToken(); int k = (int) in.nval;
        PriorityQueue<Integer> heap = new PriorityQueue<>(k); // min-heap
        for (int i = 0; i < n; i++) {
            in.nextToken();
            int x = (int) in.nval;
            if (heap.size() < k) {
                heap.offer(x);
            } else if (x > heap.peek()) {
                heap.poll();
                heap.offer(x);
            }
        }
        int sz = heap.size();
        int[] out = new int[sz];
        for (int i = sz - 1; i >= 0; i--) out[i] = heap.poll(); // ascending
        StringBuilder sb = new StringBuilder();
        for (int i = sz - 1; i >= 0; i--) {              // print descending
            if (i < sz - 1) sb.append(' ');
            sb.append(out[i]);
        }
        System.out.println(sb);
    }
}

