import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine().trim());
        int[] v = new int[n];
        StringTokenizer st = new StringTokenizer(br.readLine());
        for (int i = 0; i < n; i++) v[i] = Integer.parseInt(st.nextToken());
        long broken = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (i == j) continue;
                int sub = v[i] - v[j];                 // may overflow
                int subSign = Integer.signum(sub);
                int correct = Integer.compare(v[i], v[j]);
                if (subSign != correct) broken++;
            }
        }
        if (broken == 0) System.out.println("OK");
        else System.out.println("BROKEN " + broken);
    }
}
